+        compare_case(
+            "case_boolmask_sparse",
+            15,
+            FlatIterIndex::BoolMask((0..15).map(|idx| idx % 4 == 1).collect()),
+        ),
+        compare_case(
+            "case_boolmask_length_mismatch",
+            12,
+            FlatIterIndex::BoolMask(vec![true, false, true]),
+        ),
+        compare_case(
+            "case_fancy_out_of_bounds",
+            8,
+            FlatIterIndex::Fancy(vec![0, 2, 9]),
+        ),
+    ]
