+        compare_case("case_rank_lt_2", &[4]),
+        compare_case("case_budget_overflow", &[MAX_BATCH_SHAPE_CHECKS + 1, 2, 2]),
+        compare_case("case_mul_overflow", &[usize::MAX, usize::MAX, 2, 2]),
